local TD = TD.td1madao["ydj_dst_td1madao"] local myComponent = Class(function(self, inst)     self.inst = inst end) function myComponent:addLongBuff(buffName, periodFn)     if TD.isStr(buffName) and TD.isFn(periodFn) and not TD.cpr(self.inst):common_hasTask(buffName) then         TD.cpr(self.inst):common_addTask(buffName, function()             periodFn(self.inst)         end, 1)     end end function myComponent:removeLongBuff(buffName)     if TD.isStr(buffName) then         TD.cpr(self.inst):common_removeTask(buffName)     end end function myComponent:addBuff(buffName, startFn, periodFn, endFn, timeout)     local player = self.inst     if TD.isStr(buffName) and TD.isPos(timeout) then         local buffName = string.format("%s_addBuff_%s", TD.CHAR, buffName)         local startFnName = string.format("%s_startFn", buffName)         local periodFnName = string.format("%s_periodFnName", buffName)         local endFnName = string.format("%s_endFnName", buffName)         self:removeBuff(buffName)         TD.ctm(player, function(comp)             comp:common_removeTask(startFnName)             comp:common_removeTask(periodFnName)             comp:common_removeTask(endFnName)             if TD.isFn(startFn) then                 startFn(player)             end             if TD.isFn(periodFn) then                 local periodFnPack = function()                     periodFn(player)                 end                 comp:common_period(0.5, periodFnPack, periodFnName, timeout)             end             if TD.isFn(endFn) then                 local endFnPack = function()                     endFn(player)                     self:removeBuff(buffName)                 end                 comp:common_task(timeout, endFnPack, endFnName)             end         end)     end end function myComponent:removeBuff(buffName)     local player = self.inst     if TD.isStr(buffName) then         local buffName = string.format("%s_addBuff_%s", TD.CHAR, buffName)         local startFnName = string.format("%s_startFn", buffName)         local periodFnName = string.format("%s_periodFnName", buffName)         local endFnName = string.format("%s_endFnName", buffName)         TD.ctm(player, function(comp)             comp:common_removeTask(startFnName)             comp:common_removeTask(periodFnName)             comp:common_removeTask(endFnName)         end)     end end return myComponent 